"""
MKT Christ Commentary — Isaiah chapters 5–8
Run: python3 scripts/zc-christ-isaiah-5-8.py

Christological concentration:
- ch 5: Vineyard Song directly quoted in Matt 21:33-41 (parable of tenants);
  John 15:1-5 (true vine); six woes structure underlies Matt 23 woes
- ch 6: John 12:41 says Isaiah "saw his [Christ's] glory"; Isa 6:9-10 is the
  most-cited OT passage in the NT (Matt 13:14-15; Mark 4:12; Luke 8:10;
  John 12:40; Acts 28:26-27; Rom 11:8); Rev 4:8 (trisagion)
- ch 7: Matt 1:22-23 cites the Immanuel sign (7:14) as fulfilled in the
  virgin birth; ʿImmānûʾēl resonates through chs 7-8
- ch 8: Heb 2:13 quotes 8:17-18 as Christ speaking; 8:14 = stone of stumbling
  (Rom 9:33; 1 Pet 2:8); 8:6 Shiloah → John 9 pool of Siloam

Note: Isaiah 7:14 is already present in output — merge_comm skips it safely.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "5": {
    "1": '<p>The Song of the Vineyard opens with the prophet speaking on behalf of his "beloved" (<em>dôdî</em>) — a term of intimate affection. Jesus retells this parable in Matt 21:33-41, making explicit that the vineyard is Israel, the owner is God, and the rejected stone (21:42) is the Son. In John 15:1-5 Jesus transforms the vineyard into a vine: "I am the true vine, and my Father is the vinedresser" — where Israel failed to yield the grapes of justice (5:7), Christ is the vine that produces fruit in those who abide in him. The beloved/owner distinction in Isaiah anticipates the Trinitarian relation: the Father tends the vineyard through the Son.</p>',
    "2": '<p>"He dug it and cleared it of stones, and planted it with choice vines; he built a watchtower in the midst of it, and hewed out a wine vat in it." The preparation of the vineyard is extravagant — every provision made for fruitfulness. In Matt 21:33, Jesus reproduces the tower and vat details from this verse exactly, making the connection unmistakable. The care invested in preparation is the theological ground of the owner\'s subsequent reckoning: the question in v.4, "what more was there to do for my vineyard that I have not done in it?" parallels the divine complaint underlying the incarnation — God gave everything, including his Son.</p>',
    "3": '<p>"And now, O inhabitants of Jerusalem and men of Judah, judge between me and my vineyard." The appeal to the hearers to judge their own case is a rhetorical trap similar to Nathan\'s parable (2 Sam 12:1-7), where David condemns himself before he realizes it. In the NT, the parable of the tenants (Matt 21:40-41) uses the same device: Jesus asks "what will the owner do to those tenants?" and the chief priests answer their own condemnation ("he will put those wretches to a miserable death"). The legal form — YHWH as plaintiff, Israel as defendant — is fulfilled in the passion narrative where the roles are inverted: the true Heir is put on trial by his own tenants.</p>',
    "4": '<p>"What more was there to do for my vineyard, that I have not done in it?" The rhetorical question has no answer — every provision was made. In the light of the incarnation, the NT reads this as the question behind the sending of the Son: "last of all he sent his son, saying, \'They will respect my son.\'" (Matt 21:37). When the son is killed, the question of 5:4 is answered eschatologically: nothing more was withheld, and the rejection of the Son reveals the full depth of covenant unfaithfulness. Heb 1:1-2 frames the Son as the definitive final word after all the previous provisions of prophets.</p>',
    "5": '<p>"And now I will tell you what I will do to my vineyard. I will remove its hedge, and it shall be devoured; I will break down its wall, and it shall be trampled down." The removal of divine protection is the judgment. In Luke 13:6-9, the fig-tree parable extends the vineyard\'s reprieve: "let it alone this year also" — but the final removal remains possible. The trampling of Jerusalem by the nations in Luke 21:24 ("Jerusalem will be trampled underfoot by the Gentiles") echoes this Isaianic trampling-down; the siege of AD 70 is the historical fulfillment of the removed hedge.</p>',
    "6": '<p>"I will make it a waste; it shall not be pruned or hoed, and briers and thorns shall grow up; I will also command the clouds that they rain no rain upon it." The cessation of rain anticipates the drought-judgment pattern of Elijah\'s ministry (1 Kings 17:1; Jas 5:17-18) and the two witnesses of Rev 11:6 ("they have the power to shut the sky, that no rain may fall during the days of their prophesying"). The divine command over the clouds anticipates Christ who comes "on the clouds of heaven with power and great glory" (Matt 24:30) — cloud-command is a prerogative of the divine Son.</p>',
    "7": '<p>"For the vineyard of YHWH of hosts is the house of Israel, and the men of Judah are his pleasant planting; and he looked for justice (<em>mišpāṭ</em>), but behold, bloodshed (<em>mišpāḥ</em>); for righteousness (<em>ṣĕdāqâ</em>), but behold, an outcry (<em>ṣĕʿāqâ</em>)." The wordplay seals the parable\'s meaning. Jesus\'s woe against the scribes and Pharisees (Matt 23:23) — "you have neglected the weightier matters of the law: justice and mercy and faithfulness" — is a direct application of the vineyard\'s failure. The church as the new vineyard (Matt 21:43: "the kingdom will be given to a people producing its fruits") must not repeat the bloodshed/outcry pattern.</p>',
    "8": '<p>"Woe to those who join house to house, who add field to field, until there is no more room, and you are made to dwell alone in the midst of the land." The first woe targets covetous accumulation. Jesus\'s parable of the rich fool (Luke 12:16-21: "I will tear down my barns and build larger ones") applies the same critique. The "woe" form itself reappears in Jesus\'s Sermon on the Plain (Luke 6:24-26: "woe to you who are rich") and the woes against the scribes (Matt 23:13-36), making the Isaianic woe-series the structural template for Christ\'s prophetic denunciations.</p>',
    "9": '<p>"YHWH of hosts has sworn in my hearing: Surely many houses shall be desolate, large and beautiful houses, without inhabitant." Jesus weeps over Jerusalem: "Behold, your house is left to you desolate" (Matt 23:38; Luke 13:35) — the temple itself, the ultimate "great and beautiful house," falls under the Isaianic judgment. The divine oath (<em>nišbaʿ Yhwh ṣĕḇāʾôt bĕʾoznāy</em>) emphasizes the certainty of the word; Heb 6:13-17 makes YHWH\'s oath-taking the ground of Christian hope in the unchangeable promise.</p>',
    "10": '<p>"For ten acres of vineyard shall yield but one bath, and a homer of seed shall yield but an ephah." The agricultural curse reverses covenant blessing (Lev 26:3-5). In the NT, the seed-parable tradition (Mark 4:8: thirty, sixty, and a hundredfold yield) is the opposite pole — the kingdom of God yields a hundredfold increase where covenant-breaking yields a hundredfold reduction. Christ is the one who reverses the curse: his death is the seed that falls into the ground and produces much fruit (John 12:24).</p>',
    "11": '<p>"Woe to those who rise early in the morning, that they may run after strong drink, who tarry late into the evening as wine inflames them!" The second woe targets the culture of revelry that obliterates discernment. Jesus\'s warning in Luke 21:34 — "watch yourselves lest your hearts be weighed down with dissipation and drunkenness... and that day come upon you suddenly like a trap" — applies this woe to eschatological watchfulness. Paul echoes it in 1 Thess 5:6-7: "let us not sleep, as others do, but let us keep awake and be sober."</p>',
    "12": '<p>"They have lyre and harp, tambourine and flute and wine at their feasts, but they do not regard the deeds of YHWH, or see the work of his hands." The inability to "see the works of YHWH" amid abundance is the diagnostic failure. Jesus\'s repeated call to "have eyes to see" (Matt 13:16; Mark 8:18) addresses this blindness. The works of God that are unregarded are Jesus\'s own miracles — he reproaches the cities where he did his mighty works "because they did not repent" (Matt 11:20). Luke 16:19-31 (the rich man who feasted daily and missed the beggar at his gate) embodies the failure of 5:12.</p>',
    "13": '<p>"Therefore my people go into exile for lack of knowledge; their honored men go hungry, and their multitude is parched with thirst." The lack of knowledge is remedied by Christ who is the wisdom of God (1 Cor 1:30) and who taught "as one who had authority" (Matt 7:29). The hunger and thirst of the exile are reversed: "blessed are those who hunger and thirst for righteousness, for they shall be satisfied" (Matt 5:6); "I am the bread of life; whoever comes to me shall not hunger" (John 6:35).</p>',
    "14": '<p>"Therefore Sheol has enlarged its throat and opened its mouth beyond measure, and the nobility of Jerusalem and her multitude go down." Sheol expanding to receive the condemned is reversed in the resurrection. Christ descends to Sheol (Acts 2:27, 31: Peter quotes Ps 16:10) and conquers it from within. Rev 1:18 presents the risen Christ holding "the keys of Death and Hades" — the one who entered the enlarged Sheol now controls its gates, and the gates of Hell shall not prevail against his church (Matt 16:18).</p>',
    "15": '<p>"Man is humbled, and each one is brought low, and the eyes of the haughty are brought low." The repeated humbling theme of Isaiah is expressed in the Magnificat: "he has brought down the mighty from their thrones and exalted those of humble estate" (Luke 1:52). The kenosis of Christ (Phil 2:6-8: "he humbled himself by becoming obedient to the point of death") is the ultimate example of chosen lowering — the one who could not be brought low from without lowered himself voluntarily, and was therefore exalted above all.</p>',
    "16": '<p>"But YHWH of hosts is exalted in justice, and the Holy God shows himself holy in righteousness." John 5:22-27 states that the Father has given all judgment to the Son "so that all may honor the Son, just as they honor the Father." The cross is simultaneously the judgment of sin and the exaltation of the one who bears it: "now is the judgment of this world... And I, when I am lifted up from the earth, will draw all people to myself" (John 12:31-32). The "Holy God" who shows himself holy in judgment is the same Holy One whose holiness is mediated through the Servant.</p>',
    "17": '<p>"Then shall the lambs graze as in their pasture, and nomads shall eat among the ruins of the rich." John 10:1-18 applies the shepherd/sheep complex to Christ as the one who gives life to the sheep. Rev 7:17 pictures the Lamb at the center of the throne shepherding those who came out of the great tribulation to "springs of living water" — the lamb who was slain becomes the shepherd who leads. The nomads eating among the ruins is the reversal of the land-grabbers of v.8.</p>',
    "18": '<p>"Woe to those who draw iniquity with cords of falsehood, who draw sin as with cart ropes." The third woe characterizes sin as something actively dragged along — habituated transgression. John 8:34 — "everyone who practices sin is a slave to sin" — captures the bondage that the cord/rope image suggests. The "cords of falsehood" anticipates the binding of Jesus at Gethsemane (John 18:12: "they bound him") — the one who frees from sin\'s ropes is himself bound by those who serve sin.</p>',
    "19": '<p>"Who say: \'Let him be quick, let him speed his work that we may see it.\'" The mocking demand for divine action is the voice of practical atheism. 2 Pet 3:3-4 identifies this as the eschatological mockers\': "scoffers will come in the last days... saying, \'Where is the promise of his coming?\'" The mockers of Isaiah 5:19 reappear beneath the cross: "he trusts in God; let God deliver him now, if he desires him" (Matt 27:43) — the identical demand for immediate divine vindication, refused so that the deeper divine purpose can be accomplished.</p>',
    "20": '<p>"Woe to those who call evil good and good evil, who put darkness for light and light for darkness." The fourth woe targets moral inversion. Jesus\'s warnings about false prophets (Matt 7:15-23) and the Pharisees\' attribution of his works to Beelzebul (Matt 12:24) — calling good works demonic — is the NT manifestation. The warning about the unforgivable sin (Matt 12:31-32) is the eschatological consequence of the Isaiah 5:20 inversion: calling the work of the Holy Spirit evil places one beyond the categories of repentance.</p>',
    "21": '<p>"Woe to those who are wise in their own eyes, and shrewd in their own sight!" The fifth woe inverts the wisdom tradition. Paul applies this directly: "Let no one deceive himself. If anyone among you thinks that he is wise in this age, let him become a fool that he may become wise. For the wisdom of this world is folly with God" (1 Cor 3:18-19). In 1:19-21, Paul argues the gospel exposes human wisdom\'s bankruptcy: "I will destroy the wisdom of the wise" (citing Isa 29:14). Christ crucified is the wisdom of God that makes human cleverness foolish.</p>',
    "22": '<p>"Woe to those who are heroes at drinking wine, and valiant men in mixing strong drink." The sixth woe targets false heroism — courage redirected from covenant faithfulness to competitive drinking. The Gethsemane scene inverts this: the disciples sleep while Jesus takes the cup of suffering alone (Matt 26:40). The cup of wine that the sixth-woe "heroes" master becomes the cup of the Lord\'s Supper (Luke 22:20) and the cup of suffering that Jesus drinks — the true heroism is receiving the cup from the Father.</p>',
    "23": '<p>"Who acquit the guilty for a bribe, and deprive the innocent of his right!" The judicial corruption condemned in the sixth woe is dramatized at the passion: Pilate, who "found no guilt" in Jesus (Luke 23:4), ultimately releases Barabbas (a guilty man) and condemns the innocent. The bribe in view is Judas\'s thirty pieces of silver (Matt 26:15). At the cross, Isa 53:11 is fulfilled: the servant "shall make many righteous" — the one unjustly condemned acquits the guilty, reversing the corruption described here.</p>',
    "24": '<p>"Therefore, as the tongue of fire devours the stubble... for they have rejected the Torah of YHWH of hosts, and have despised the word of the Holy One of Israel." John 12:48 — "the word that I have spoken will judge him on the last day" — presents Christ as the Torah/Word whose rejection is self-condemnation. The fire that devours stubble becomes John the Baptist\'s announcement: "he will baptize you with the Holy Spirit and fire... he will burn the chaff with unquenchable fire" (Matt 3:11-12).</p>',
    "25": '<p>"Therefore the anger of YHWH was kindled against his people, and he stretched out his hand against them and struck them... For all this his anger has not turned away, and his hand is still stretched out." The "hand stretched out" refrain is a counterpoint to YHWH\'s hand stretched out in welcome (65:2; Rom 10:21). In the Passion, both stances are held simultaneously: the outstretched hand of welcome (Luke 15:20) and the hand of judgment are reconciled at the cross where God "did not spare his own Son but gave him up for us all" (Rom 8:32).</p>',
    "26": '<p>"He will raise a signal for nations far away, and whistle for them from the ends of the earth; and behold, quickly, speedily they come!" The signal-raising to distant nations is the gathering of Gentiles — the great commission (Matt 28:18-20). Rev 14:6 presents "an angel flying directly overhead, with an eternal gospel to proclaim to those who dwell on earth, to every nation and tribe and language and people." The speed ("quickly, speedily") anticipates Christ\'s promised return: "Surely I am coming soon" (Rev 22:20).</p>',
    "27": '<p>"None is weary, none stumbles, none slumbers or sleeps, not a waistband is loose, not a sandal strap broken." The invading army\'s readiness is applied in the NT to spiritual watchfulness: "Dress yourselves for action and keep your lamps burning" (Luke 12:35); "stand therefore, having fastened on the belt of truth... and, as shoes for your feet, having put on the readiness given by the gospel of peace" (Eph 6:14-15). The soldier who never stumbles anticipates Jude 24: "to him who is able to keep you from stumbling."</p>',
    "28": '<p>"Their arrows are sharp, all their bows bent, their horses\' hooves seem like flint, and their wheels like the whirlwind." The battle imagery foreshadows Revelation\'s war imagery: the four horsemen (Rev 6:1-8), the armies on white horses (Rev 19:14). In NT eschatology, the sharp arrows of divine judgment are overcome by the shield of faith (Eph 6:16: "with which you can extinguish all the flaming darts of the evil one").</p>',
    "29": '<p>"Their roaring is like a lion, like young lions they roar; they growl and seize their prey; they carry it off, and none can rescue." The lion imagery applies Christologically in two directions. As judge, Christ is "the Lion of the tribe of Judah" (Rev 5:5). As protector, John 10:28-29: "no one will snatch them out of my hand... no one is able to snatch them out of the Father\'s hand." The prey that "none can rescue" from the invader becomes the sheep that "none can snatch" from the divine hand.</p>',
    "30": '<p>"And they will growl over it on that day, like the growling of the sea. And if one looks to the land, behold, darkness and distress; and the light is darkened by its clouds." The darkness at the end of Isaiah 5 anticipates the darkness at the crucifixion (Matt 27:45) and the Day of the Lord (Joel 2:2). Luke 21:25 uses the sea-roar and distress as signs of the Son of Man\'s coming — the clouds that darken in 5:30 are the same clouds on which the Son of Man returns (Matt 24:30).</p>',
  },
  "6": {
    "1": '<p>"In the year that King Uzziah died I saw the Lord sitting upon a throne, high and lifted up." John 12:41 — "Isaiah said these things because he saw his glory and spoke of him" — is the NT\'s explicit identification: the enthroned Lord of Isaiah 6:1 is Christ. John\'s context makes this unmistakable: he cites 6:10 in 12:40 and immediately identifies it as speaking of Christ\'s glory. The "high and lifted up" (<em>rām wĕniśśāʾ</em>) anticipates 52:13 where the Servant "shall be high and lifted up" using the same words — the throne vision and the Servant exaltation are the same divine glory seen from two vantage points.</p>',
    "2": '<p>"Above him stood the seraphim. Each had six wings: with two he covered his face, and with two he covered his feet, and with two he flew." The seraphim of Isaiah 6:2 become the four living creatures of Rev 4:8 ("each of them with six wings, full of eyes all around and within") who encircle the throne of God and the Lamb. The seraphim\'s covering of faces before divine glory anticipates the NT theme of beholding glory directly: "we all, with unveiled face, beholding the glory of the Lord, are being transformed into the same image" (2 Cor 3:18).</p>',
    "3": '<p>"Holy, holy, holy is YHWH of hosts; the whole earth is full of his glory!" The trisagion is taken up in Rev 4:8: "Holy, holy, holy, is the Lord God Almighty, who was and is and is coming!" — the Revelation version adds temporal extension that applies to Christ. "The whole earth full of his glory" is fulfilled in the incarnation: "the Word became flesh and dwelt among us, and we have seen his glory" (John 1:14). The seraphic proclamation is the worship of the pre-incarnate Son; John saw it and testified.</p>',
    "4": '<p>"And the foundations of the thresholds shook at the voice of him who called, and the house was filled with smoke." The threshold-shaking at the divine voice anticipates: the earthquake at the resurrection (Matt 28:2); the Pentecost event where "suddenly there came from heaven a sound like a mighty rushing wind, and it filled the entire house" (Acts 2:2); and Rev 15:8 where "the sanctuary was filled with smoke from the glory of God" — a deliberate echo of Isaiah 6:4 applied to the return of Christ\'s glory.</p>',
    "5": '<p>"Woe is me! For I am lost; for I am a man of unclean lips... for my eyes have seen the King, YHWH of hosts!" The creature\'s dissolution before the holy presence is consistently present in NT encounters with Christ: Peter\'s "Depart from me, for I am a sinful man, O Lord" (Luke 5:8); John falling "as though dead" before the risen Christ (Rev 1:17); Paul blinded on the Damascus road (Acts 9:3-4). The "unclean lips" healed by the coal (v.7) anticipate Christ\'s purification of the unclean at his touch (Mark 1:40-42).</p>',
    "6": '<p>"Then one of the seraphim flew to me, having in his hand a burning coal that he had taken with tongs from the altar." The seraph mediates purification from the altar — the altar being the place of sacrifice. Heb 9:14 ("the blood of Christ... purify our conscience from dead works") continues this altar-to-purification logic. The flight of the seraph with the coal connects to the proclamation of the gospel by those sent (Rom 10:15, "how beautiful are the feet of those who preach the good news").</p>',
    "7": '<p>"He touched my mouth and said: \'Behold, this has touched your lips; your guilt is taken away, and your sin atoned for.\'" The touch that removes guilt and atones is the purification that precedes commission. In the NT, forgiveness precedes and grounds mission: "your sins are forgiven... go in peace" (Luke 7:48-50). Jesus touches the untouchable (lepers, the dead) and pronounces forgiveness and healing — the coal-touch of Isaiah 6:7 becomes the healing touch of Christ. The atonement vocabulary (<em>kuppār</em>) connects to the priestly Christology of Heb 9:26.</p>',
    "8": '<p>"And I heard the voice of the Lord saying, \'Whom shall I send, and who will go for us?\' Then I said, \'Here I am! Send me.\'" The divine council\'s "us" and the prophet\'s commission anticipate the Trinitarian sending. John 17:18 — "as you sent me into the world, so I have sent them into the world" — continues the pattern: the Father sends the Son (John 20:21), the Son sends the Spirit (John 15:26). Christ\'s "Behold, I have come to do your will, O God" (Heb 10:7, citing Ps 40:7-8) is the full embodiment of the prophetic "Here I am."</p>',
    "9": '<p>"Go, and say to this people: \'Keep on hearing, but do not understand; keep on seeing, but do not perceive.\'" This is the most frequently cited OT text in the NT: Matt 13:14-15; Mark 4:12; Luke 8:10; John 12:40; Acts 28:26-27; Rom 11:8. The programmatic hardening commission begins with the Servant\'s own ministry — the parables function to hide meaning from those who refuse to see. The hardening is judicial: persistent rejection of light results in inability to perceive it. John 12:40 adds: "Isaiah said these things because he saw his glory and spoke of him" — the one who hardens is Christ himself, as he was the Lord in 6:1.</p>',
    "10": '<p>"Make the heart of this people dull, and their ears heavy, and blind their eyes; lest they see with their eyes, and hear with their ears, and understand with their hearts, and turn and be healed." John 12:40 quotes this verse and adds: "Isaiah said these things because he saw his glory and spoke of him" (12:41) — making the hardening the judgment of the pre-incarnate Christ. The healing that hardening prevents is the healing Jesus offers throughout his ministry. Matt 13:15 ends the citation with the positive: "lest they turn, and I would heal them" — the healing remains possible for those who turn; the hardening terminal only for final refusal.</p>',
    "11": '<p>"Then I said, \'How long, O Lord?\' And he said: \'Until cities lie waste without inhabitant.\'" The "how long?" question is the eschatological lament. In Rev 6:10, the souls under the altar cry "how long, O Lord, holy and true, before you will judge and avenge our blood?" — the prophetic "how long?" of Isaiah 6:11 becomes the martyrs\' cry. Christ\'s own "how long am I to bear with you?" (Matt 17:17) echoes the divine patience. The answer in both Isaiah and Revelation: until the full measure of judgment is accomplished.</p>',
    "12": '<p>"And YHWH removes people far away, and the forsaken places are many in the midst of the land." The scattering judgment is the reverse of the promised regathering. In NT terms: "I have other sheep that are not of this fold. I must bring them also" (John 10:16). The "forsaken places" become the sites of the new community — Acts 8:4, "now those who were scattered went about preaching the word," turns the dispersion into mission, fulfilling the gathering of the scattered that Isaiah promised.</p>',
    "13": '<p>"And though a tenth remain in it, it will be burned again, like a terebinth or an oak, whose stump remains when it is felled. The holy seed is its stump." The holy seed (<em>zeraʿ qōdeš</em>) is the remnant Paul addresses in Rom 11:5: "at the present time there is a remnant, chosen by grace." The stump also anticipates the Servant: 11:1 describes "a shoot from the stump of Jesse" — the Messiah from the apparently dead royal line. The cutting-down and sprouting is the death-and-resurrection pattern: the holy seed that falls into the ground and dies bears much fruit (John 12:24).</p>',
  },
  "7": {
    "1": '<p>The Syro-Ephraimite crisis (735 BCE): Rezin of Syria and Pekah of Israel march against Jerusalem, and the Davidic dynasty trembles. The political threat to the Davidic line is the immediate context for the Immanuel sign. Matt 1:1 opens with "the book of the genealogy of Jesus Christ, the son of David" — the survival of the Davidic line through this and every subsequent crisis is the precondition for the incarnation. Every attack on the Davidic house is implicitly an attack on the future Messiah.</p>',
    "2": '<p>"The heart of Ahaz and the heart of his people shook as the trees of the forest shake before the wind." The fear of Ahaz before the political threat is the opposite of the faith called for in 7:9. Jesus\'s "why are you afraid, O you of little faith?" (Matt 8:26) parallels the shaking of Ahaz — both are called to trust YHWH in a crisis. The peace that passes understanding (Phil 4:6-7) — "do not be anxious about anything" — is the NT resolution of the political anxiety that Isaiah diagnoses as faithlessness.</p>',
    "3": '<p>Isaiah goes to meet Ahaz with his son Shear-jashub ("a remnant shall return") — prophetic naming as enacted oracle. Matt 1:21 continues this tradition: "you shall call his name Jesus, for he will save his people from their sins" — the child\'s name is the prophetic word in compact form. The highway to the Washer\'s Field connects to 40:3 ("prepare the way"), linking the Syro-Ephraimite crisis narrative to the long arc of salvation history that culminates in Christ.</p>',
    "4": '<p>"Be careful, be quiet, do not fear, and do not let your heart be faint because of these two smoldering stumps of firebrands." The prophetic "do not fear" (<em>ʾal-tîrāʾ</em>) is the most common divine command in both testaments. Jesus\'s "fear not" occurs throughout the gospels (Matt 10:31; Luke 12:7,32; John 14:27: "do not let your hearts be troubled, and do not let them be afraid"). The prophetic reframe of political reality from the divine perspective is Christ\'s own practice: "in the world you will have tribulation, but take heart; I have overcome the world" (John 16:33).</p>',
    "5": '<p>"Because Syria, with Ephraim and the son of Remaliah, has devised evil against you." The naming of the threat in order to diminish it is a feature of prophetic speech. In Rev 2:10, Christ names the specific threat to Smyrna: "the devil is about to throw some of you into prison... Be faithful unto death." Jesus\'s "fear not" is always specific — he names what his people fear and reframes it within the larger narrative of divine sovereignty over all human plots.</p>',
    "6": '<p>"Let us go up against Judah and terrify it, and let us conquer it for ourselves, and set up the son of Tabeel as king in it." The plan to overthrow the Davidic dynasty and install a puppet king is the recurring Serpent\'s strategy to destroy the messianic line. Herod\'s slaughter of the innocents (Matt 2:16-18), Pilate\'s offer of Barabbas (Matt 27:20-26) — all operate in the same pattern. The preservation of the Davidic line through every attack is the divine faithfulness that makes the incarnation possible.</p>',
    "7": '<p>"Thus says the Lord YHWH: It shall not stand, and it shall not come to pass." The divine veto of the political conspiracy is absolute. The same divine "no" underlies the resurrection: "you killed the Author of life, but God raised him from the dead" (Acts 3:15). Every human plan to neutralize Christ — Herod\'s massacre, Pilate\'s execution, the sealed tomb — meets this divine counter. Acts 5:38-39 generalizes: "if it is of God, you will not be able to overthrow it."</p>',
    "8": '<p>"For the head of Syria is Damascus, and the head of Damascus is Rezin. And within sixty-five years Ephraim will be shattered from being a people." The prophetic precision grounds the credibility of all prophetic speech. Peter\'s argument at Pentecost (Acts 2:30-31: "knowing that God had sworn with an oath to him that he would set one of his descendants on his throne, he foresaw and spoke about the resurrection of the Christ") rests on prophetic precision of this kind — earlier prophecy fulfilled in history validates the unprecedented promise of resurrection.</p>',
    "9": '<p>"And the head of Samaria is the son of Remaliah. If you are not firm in faith, you will not be firm at all." The Hebrew wordplay <em>taʾămînû / tēʾāmēnû</em> (believe / be established) is compressed Isaianic faith-theology. Paul\'s fundamental category of <em>pistis</em> (faith) in Romans is grounded in this Isaianic usage: "The righteous shall live by faith" (Rom 1:17). Heb 11:1-3 similarly grounds the hall-of-faith survey in the Isaianic understanding of faith as the stabilizing foundation that invisible things provide for visible reality.</p>',
    "10": '<p>"Again YHWH spoke to Ahaz." The renewed divine address to the faithless king sustains a patience that the narrative will show Ahaz rejects. The persistence of divine address despite faithlessness is the pattern of grace: Rom 5:8, "God shows his love for us in that while we were still sinners, Christ died for us." The second approach to Ahaz is mirrored in Peter\'s threefold restoration (John 21:15-17) after threefold denial — faithlessness does not exhaust the divine approach.</p>',
    "11": '<p>"Ask a sign of YHWH your God; let it be deep as Sheol or high as heaven." The generous offer — any sign, from death\'s depths to heaven\'s heights — corresponds to the depth and height of the sign ultimately given: the Immanuel born of a virgin who descends into Sheol and ascends to heaven. Eph 3:18-19 prays that believers would "comprehend... the breadth and length and height and depth, and to know the love of Christ" — the sign offered to Ahaz spans the same dimensions Paul uses to describe the inexhaustible reach of Christ\'s love.</p>',
    "12": '<p>"But Ahaz said, \'I will not ask, and I will not put YHWH to the test.\'" Ahaz\'s refusal is pious in form but faithless in substance — he has already decided to ask Tiglath-pileser for help (2 Kings 16:7-8). The Jesus who refuses to test YHWH (Matt 4:7: "you shall not put the Lord your God to the test") does so from genuine faith, not political calculation. The contrast highlights the Servant\'s authentic trust: where Ahaz uses the language of faith to cover faithlessness, Jesus practices the faith Ahaz refused.</p>',
    "13": '<p>"And he said, \'Hear then, O house of David! Is it too little for you to weary men, that you weary my God also?\'" The "house of David" address widens the sign beyond Ahaz to the entire Davidic dynasty. Matt 1:1 opens the NT with "Jesus Christ, the son of David" — the genealogy is precisely the "house of David" to whom the sign is given. The wearying of God by faithlessness is echoed in Heb 3:17-19: "with whom was he provoked for forty years? Was it not with those who sinned?"</p>',
    "14": '<p>"Therefore the Lord himself will give you a sign. Behold, the virgin (<em>hāʿalmâ</em>) shall conceive and bear a son, and shall call his name Immanuel." Matthew 1:22-23 cites this verse as fulfilled in the birth of Jesus: "\'Behold, the virgin (<em>parthenos</em>) shall conceive and bear a son, and they shall call his name Immanuel\' (which means, God with us)." The name Immanuel — "God with us" — is the supreme Christological title: the divine person present with his people, which John 1:14 expresses as "the Word became flesh and dwelt (<em>eskēnōsen</em>, tabernacled) among us." Matthew\'s Immanuel bookend (1:23 and 28:20: "I am with you always") frames the entire Gospel as the Immanuel narrative.</p>',
    "15": '<p>"He shall eat curds and honey when he knows how to refuse the evil and choose the good." The one who "knows how to refuse the evil and choose the good" is the one who "was tempted in every way as we are, yet without sin" (Heb 4:15). Jesus\'s forty-day fast (Matt 4:1-11), where he refuses the devil\'s temptations, fulfills the moral capacity described here. The Immanuel child who chooses good and refuses evil is the Servant who "had done no violence, and there was no deceit in his mouth" (Isa 53:9).</p>',
    "16": '<p>"For before the boy knows how to refuse the evil and choose the good, the land whose two kings you dread will be deserted." The sign operates on two timescales — near-term (the Assyrian resolution within years) and far-term (the Immanuel who is literally "God with us"). This two-horizon structure of prophetic fulfillment is the key to understanding NT citation of OT prophecy: the near fulfillment is the type; the far fulfillment in Christ is the antitype. The historical specificity of the near sign grounds the credibility of the far promise.</p>',
    "17": '<p>"YHWH will bring upon you and upon your people and upon your father\'s house such days as have not come since the day that Ephraim departed from Judah — the king of Assyria." The judgment following Ahaz\'s faithless alliance with Assyria is the consequence of refusing the divine sign. Jesus warns in the same pattern: Matt 23:38, "your house is left to you desolate," and 24:21, "then there will be great tribulation, such as has not been from the beginning of the world." The structure is exact: refusing the sign brings the very disaster the sign was meant to prevent.</p>',
    "18": '<p>"In that day YHWH will whistle for the fly that is at the end of the streams of Egypt, and for the bee that is in the land of Assyria." The fly from Egypt and bee from Assyria are imperial powers summoned as instruments of judgment. In Rev 9:3-11, locusts from the abyss combine insect and military imagery as divine judgment agency. The nations as divine instruments of judgment is a consistent OT pattern — Hab 1:6-11 (Babylon as divine instrument) — fulfilled in Christ\'s Olivet Discourse where the nations are simultaneously agents of judgment and subjects of the same judgment.</p>',
    "19": '<p>"And they will all come and settle in the steep ravines, and in the clefts of the rocks, and on all the thornbushes, and on all the pastures." The swarming occupation of the land echoes Joel 2 (the locust army) and Rev 9. The "clefts of the rocks" where the invaders shelter echoes 2:19-21 where the proud hide in caves from the Day of YHWH — the same geography serves both the agents of judgment and those fleeing from it. Those who reject the Immanuel find no safe cleft on the day of the Lamb\'s wrath (Rev 6:16-17).</p>',
    "20": '<p>"In that day the Lord will shave with a razor that is hired beyond the River — with the king of Assyria." YHWH "hires" Assyria as his own tool; the cross reveals that what appears as the hiring of human violence against the Messiah is in fact the divine instrument of redemption: "this Jesus, delivered up according to the definite plan and foreknowledge of God" (Acts 2:23). The shaving/degradation of the judgment-instrument becomes the degradation of the Servant himself who "gave his back to those who strike, and his cheeks to those who pluck out the beard" (Isa 50:6).</p>',
    "21": '<p>"In that day a man will keep alive a young cow and two sheep." The remnant\'s small holdings after Assyrian devastation is an image of radical simplification. In NT terms, the stripping-away that judgment accomplishes becomes the poverty that is called blessed (Matt 5:3). The early church\'s sharing of all goods (Acts 2:44-45) reproduces this radical simplification — the Assyrian stripping is voluntarily reproduced in the communal life of those who have found in Immanuel their true wealth.</p>',
    "22": '<p>"And because of the abundance of milk that they give, he will eat curds, for everyone left in the land will eat curds and honey." The same curds and honey that mark the Immanuel child (v.15) are the food of the remnant. John 6:31-35 transforms the manna-in-wilderness tradition: "the bread of God is he who comes down from heaven and gives life to the world... I am the bread of life." The remnant\'s abundance within the devastated landscape is the type of the supernatural nourishment Christ provides in the wilderness of this age.</p>',
    "23": '<p>"In that day every place where there used to be a thousand vines, worth a thousand shekels of silver, will become briers and thorns." The reversal of the vineyard — the thousand-vine estate reverting to thorns — echoes ch. 5 and anticipates the crown of thorns (Matt 27:29; John 19:2) placed on the one who is the true vine (John 15:1). The thorns of the curse (Gen 3:18) become the symbol of human mockery of the divine king — the judgment-land\'s thorns woven into a crown for the one who bears the curse.</p>',
    "24": '<p>"With bow and arrows a man will come there, for all the land will be briers and thorns." Rev 6:2 opens the seal judgments with a rider carrying a bow, who "came out conquering, and to conquer" — the bow-and-thorn imagery of the devastated land becomes the apocalyptic imagery of conquest. The desolated land awaiting the Immanuel\'s birth is the broken world into which he comes to begin the restoration; the thorns and briers are the sign of the curse he will eventually reverse.</p>',
    "25": '<p>"And as for all the hills that used to be hoed with a hoe, you will not come there for fear of briers and thorns, but they will become a place where cattle are let loose and where sheep tread." The cultivated hills becoming untended pasture is an inverted pastoral. The lost sheep who wander untended (Matt 9:36: "like sheep without a shepherd") are the fulfillment of the Immanuel-era\'s abandoned pastures. The Good Shepherd of John 10 comes to restore the tending that judgment disrupted — the overgrown hills become pasture again under his care.</p>',
  },
  "8": {
    "1": '<p>"Then YHWH said to me, \'Take a large tablet and write on it in common characters, \'Maher-shalal-hash-baz.\'" The writing of prophetic judgment on a large public tablet is an enacted oracle. Rev 1:11 commissions John to "write what you see in a book" — the same writing-as-public-witness function. The name Maher-shalal-hash-baz is the judgment counterpart to the salvation of "Immanuel" in 7:14; both are enacted in child-naming. Jesus\'s name (Matt 1:21) is the ultimate prophetic naming — the word of God compressed into a personal identity.</p>',
    "2": '<p>"And I will get reliable witnesses, Uriah the priest and Zechariah the son of Jeberechiah, to attest for me." The two witnesses required by Torah (Deut 17:6; 19:15) are the legal foundation for the prophecy\'s credibility. Jesus cites the two-witness principle in John 8:17-18: "I am the one who bears witness about myself, and the Father who sent me bears witness about me." Revelation\'s two witnesses (Rev 11:3-4) carry the same prophetic authentication function. At the passion, the false witnesses are "two" (Matt 26:60) — a perverse inversion of the Mosaic requirement against the innocent.</p>',
    "3": '<p>"And I went to the prophetess, and she conceived and bore a son. Then YHWH said to me, \'Call his name Maher-shalal-hash-baz.\'" The prophetic family as a living enacted parable foreshadows the holy family of the NT. The incarnation is itself the ultimate enacted parable: the eternal Word takes flesh in a human family (Luke 2:1-7). Isaiah\'s family of sign-children (Shear-jashub, Maher-shalal-hash-baz) is the OT precursor to the incarnate Immanuel who is the sign of all signs.</p>',
    "4": '<p>"For before the boy knows how to cry \'My father\' or \'My mother,\' the wealth of Damascus and the spoil of Samaria will be carried away before the king of Assyria." The sign\'s historical fulfillment (Assyrian conquest of Damascus, 732 BCE) establishes the prophetic word\'s reliability. Luke 1:1-4 opens with the same concern for historical reliability. The historical grounding of Isaiah\'s near signs grounds the credibility of the far signs about Immanuel — if this came true in verifiable history, so will the rest.</p>',
    "5": '<p>YHWH spoke to Isaiah again, adding to the oracle. The cumulative speaking — oracle upon oracle — is the prophetic patience that Heb 1:1 describes: "Long ago, at many times and in many ways, God spoke to our fathers by the prophets." The "many times and many ways" is the narrative of Isaiah 7-8 in miniature. "But in these last days he has spoken to us by his Son" — the multiplicity of prophetic words converges into the single Word made flesh.</p>',
    "6": '<p>"Because this people has refused the waters of Shiloah that flow gently, and rejoice over Rezin and the son of Remaliah." John 9:7 identifies the pool of Siloam (<em>Siloam</em>, translating <em>šilōaḥ</em>, "sent") as the site of the healing of the man born blind — Jesus sends him there to wash. The people who rejected the gentle waters of Shiloah (8:6) are the ones who reject the one who offers living water (John 4:10). The "sent" etymology connects to John\'s repeated use of "sent" for Jesus: "the Father who sent me."</p>',
    "7": '<p>"Therefore the Lord is bringing up against them the waters of the River, mighty and many, the king of Assyria and all his glory." The rejection of Shiloah\'s gentle waters brings the Euphrates flood. In NT apocalyptic, the demonic flood of Rev 12:15-16 parallels this: the dragon pours water like a river after the woman, to sweep her away — but the earth swallows the flood. Christ\'s mastery over the sea (Mark 4:39: "peace, be still"; Matt 14:25-26: walking on water) demonstrates sovereignty over the flood-waters that represent both judgment and hostile powers.</p>',
    "8": '<p>"And it will sweep into Judah, it will overflow and pass on, reaching even to the neck, and its outspread wings will fill the breadth of your land, O Immanuel." The flood reaching to the neck and the address "O Immanuel" is the pivot: the flood threatens the land but the land is named for Immanuel. John 16:33 — "in the world you will have tribulation, but take heart; I have overcome the world" — reproduces this logic exactly. The flood that reaches the neck of Zion is the cross that nearly swallowed the Christ — but did not.</p>',
    "9": '<p>"Be broken, you peoples, and be shattered; give ear, all you far countries; strap on your armor and be shattered." The repeated command to the nations to arm themselves and be shattered is prophetic irony. Rev 19:19-21 fulfills this: "the beast and the kings of the earth with their armies gathered to make war against him who was sitting on the horse and against his army. And the beast was captured." The nations gather against Immanuel and are shattered — the exact pattern of Psalm 2:2-4 ("the kings of the earth set themselves against YHWH and against his Anointed... he who sits in the heavens laughs").</p>',
    "10": '<p>"Take counsel together, but it will come to nothing; speak a word, but it will not stand, for God is with us (<em>ʿimmānû ʾēl</em>)." The Immanuel refrain is here explicitly rendered as a declaration: plans fail because "God is with us." Rom 8:31: "If God is for us, who can be against us?" Rom 8:38-39: "neither death nor life... nor any other created thing will be able to separate us from the love of God that is in Christ Jesus our Lord." The <em>ʿimmānû ʾēl</em> is the Christological principle that no counsel against the people of Christ can prevail.</p>',
    "11": '<p>"For YHWH spoke thus to me with his strong hand upon me, and warned me not to walk in the way of this people." The divine grip on the prophet ("his strong hand upon me") is prophetic compulsion. Jesus\'s own "I must" language — "I must proclaim the good news of the kingdom of God to the other towns also; for I was sent for this purpose" (Luke 4:43) — is the full embodiment of this compulsion. The Servant is driven by divine necessity, not by the desire for popular approval.</p>',
    "12": '<p>"Do not call conspiracy all that this people calls conspiracy, and do not fear what they fear, nor be in dread." The prophetic counter-culture: while the political class sees conspiracies and fears coalitions, the prophet is to fear YHWH alone. Jesus\'s "do not fear those who kill the body but cannot kill the soul" (Matt 10:28) is the NT expression. Acts 18:9-10: "do not be afraid, but go on speaking... for I am with you" — the Immanuel-presence banishes the political fears of Isaiah 8:12.</p>',
    "13": '<p>"But YHWH of hosts, him you shall honor as holy. Let him be your fear, and let him be your dread." 1 Pet 3:15 cites this verse directly: "in your hearts honor Christ the Lord as holy" (<em>ton Christon hagiasate</em>) — the YHWH-fear of Isaiah 8:13 is explicitly Christ-fear in Peter\'s application. Rev 1:17-18 — "when I saw him, I fell at his feet as though dead... \'Fear not, I am the first and the last, and the living one\'" — the holy fear before the risen Christ resolves into reassurance.</p>',
    "14": '<p>"And he will become a sanctuary and a stone of offense and a rock of stumbling to both houses of Israel, a trap and a snare to the inhabitants of Jerusalem." Rom 9:33 and 1 Pet 2:8 both cite this verse as fulfilled in the rejection of Christ: "\'Behold, I am laying in Zion a stone of stumbling, and a rock of offense.\'" 1 Pet 2:6-8 weaves together Isaiah 28:16 (the cornerstone), Psalm 118:22 (the rejected stone becoming cornerstone), and Isaiah 8:14 (the stumbling stone) into a unified stone-theology: the same stone that is salvation\'s foundation is the stone that causes those who refuse it to fall.</p>',
    "15": '<p>"And many shall stumble on it. They shall fall and be broken; they shall be snared and taken." Luke 20:18 — "everyone who falls on that stone will be broken to pieces, and when it falls on anyone, it will crush him" — applies the stumbling-stone imagery to the parable of the tenants. The division between those built on the rock (Matt 7:24-25) and those who stumble on it is the Christological fork in every human destiny: the same stone that is the foundation of salvation is the stone of judgment for those who reject it.</p>',
    "16": '<p>"Bind up the testimony; seal the teaching among my disciples." The sealed testimony entrusted to disciples (<em>limmudîm</em>, the taught ones — same word as 50:4) is the prototype of apostolic tradition. 2 Tim 1:14 — "guard the good deposit entrusted to you, by the Holy Spirit who dwells within us" — continues this sealing-and-guarding function. Rev 5:1-5: the sealed scroll of divine counsel that only the Lion-Lamb can open. The disciples of the Servant are the bearers of the sealed testimony across time.</p>',
    "17": '<p>"I will wait for YHWH, who is hiding his face from the house of Jacob, and I will hope in him." Hebrews 2:13 explicitly quotes this verse as Christ speaking: "I will put my trust in him." The hiding of the divine face (<em>hammastîr pānāyw</em>) reaches its extreme expression in Jesus\'s cry from the cross: "My God, my God, why have you forsaken me?" (Matt 27:46). The Servant who waits for YHWH while his face is hidden is the Christ who maintains trust through the God-forsakenness of the cross.</p>',
    "18": '<p>"Behold, I and the children whom YHWH has given me are signs and portents in Israel from YHWH of hosts." Hebrews 2:13 quotes this verse immediately after 8:17, presenting Christ as the speaker: the Servant\'s sign-children are the type of Christ\'s "children" — those given to him by the Father (John 6:37: "all that the Father gives me will come to me"; 17:6: "the people whom you gave me out of the world"). The "children" of Isaiah 8:18 are the Church, given to the Son, who are signs of the new creation.</p>',
    "19": '<p>"And when they say to you, \'Inquire of the mediums and the necromancers who chirp and mutter,\' should not a people inquire of their God? Should they inquire of the dead on behalf of the living?" The contrast between consulting the dead and inquiring of the living God is resolved definitively in the resurrection. John 11:25 — "I am the resurrection and the life; whoever believes in me, though he die, yet shall he live" — establishes Christ as the answer to the "inquiry of the dead." Heb 7:25: "he always lives to make intercession for them" — the living one holds the keys to death (Rev 1:18).</p>',
    "20": '<p>"To the teaching and to the testimony! If they will not speak according to this word, it is because they have no dawn." The Torah and testimony as the standard — "if there is no light (<em>šaḥar</em>, dawn) in them." John 8:12 — "I am the light of the world; whoever follows me will not walk in darkness" — presents Christ as the dawn-light that the teaching pointed toward. 2 Pet 1:19: "you do well to pay attention to it, as to a lamp shining in a dark place, until the day dawns and the morning star rises in your hearts."</p>',
    "21": '<p>"They will pass through the land, greatly distressed and hungry. And when they are hungry, they will be enraged and will speak contemptuously against their king and their God." The hunger and rage of the judgment era — where distress produces cursing rather than repentance — contrasts with the hunger that produces trust. The crowd that follows Jesus "because they ate their fill of the loaves" (John 6:26) but turns away when the teaching becomes demanding (6:66) reproduces the turning-away of 8:21. Only the bread of life that Christ gives satisfies to eternal life (John 6:35).</p>',
    "22": '<p>"And they will look to the earth, but behold, distress and darkness, the gloom of anguish. And they will be thrust into thick darkness." The thick darkness that ends Isaiah 8 is immediately dispelled at the opening of 9:1-2 ("the people who walked in darkness have seen a great light") — the death-darkness/resurrection-light movement. Matt 4:15-16 quotes Isaiah 9:1-2 in connection with Jesus\'s ministry in Galilee. The darkness of 8:22 is not the final word — it is the darkness before the dawn that is Jesus, "the light that shines in the darkness, which the darkness has not overcome" (John 1:5).</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    # INTENT: Verify all verses in Isaiah 5-8 mkt-christ present against interlinear
    # CHANGE? If interlinear/isaiah.json ch 5-8 verse counts change, update expected totals
    # VERIFY: Console shows complete for all 4 chapters; no MISSING output
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'isaiah.json').read_text())
    all_ok = True
    for ch in range(5, 9):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present.')

if __name__ == '__main__':
    main()
